 30→// Helper function to read expected schema from file
 31→std::string read_expected_schema(const std::string& filename) {
 32→  std::string filepath = Test::DATA_PATH + filename;
 33→  std::ifstream file(filepath);
 34→  if (!file.is_open()) {
 35→    return "";
 36→  }
