 55→TEST_F(SchemaExtractorTest, PointCloud2SchemaContainsExpectedFields) {
 56→  // Extract actual schema
 57→  std::string actual = extractor_->get_message_definition("sensor_msgs/msg/PointCloud2");
 58→  ASSERT_FALSE(actual.empty()) << "Failed to extract schema for sensor_msgs/msg/PointCloud2";
 59→
 60→  // Remove comments from schema for checking
 61→  std::string actual_no_comments = remove_comments_from_schema(actual);
 62→
 63→  // Check that all expected fields are present (newer ROS versions may add more)
 64→  EXPECT_NE(actual_no_comments.find("std_msgs/Header header"), std::string::npos);
 65→  EXPECT_NE(actual_no_comments.find("uint32 height"), std::string::npos);
 66→  EXPECT_NE(actual_no_comments.find("uint32 width"), std::string::npos);
 67→  EXPECT_NE(actual_no_comments.find("PointField[] fields"), std::string::npos);
 68→  EXPECT_NE(actual_no_comments.find("bool    is_bigendian"), std::string::npos);
 69→  EXPECT_NE(actual_no_comments.find("uint32  point_step"), std::string::npos);
 70→  EXPECT_NE(actual_no_comments.find("uint32  row_step"), std::string::npos);
 71→  EXPECT_NE(actual_no_comments.find("uint8[] data"), std::string::npos);
 72→  EXPECT_NE(actual_no_comments.find("bool is_dense"), std::string::npos);
 73→
 74→  // Check nested PointField has core constants (INT8 through FLOAT64)
 75→  EXPECT_NE(actual_no_comments.find("uint8 INT8    = 1"), std::string::npos);
 76→  EXPECT_NE(actual_no_comments.find("uint8 FLOAT64 = 8"), std::string::npos);
 77→
 78→  // Check nested Header and Time are included
 79→  EXPECT_NE(actual_no_comments.find("MSG: std_msgs/Header"), std::string::npos);
 80→  EXPECT_NE(actual_no_comments.find("MSG: builtin_interfaces/Time"), std::string::npos);
 81→  EXPECT_NE(actual_no_comments.find("string frame_id"), std::string::npos);
 82→}
