24→TopicDiscovery::TopicDiscovery(rclcpp::Node::SharedPtr node) : node_(node) {}
25→
26→std::vector<TopicInfo> TopicDiscovery::discover_topics() {
27→  std::vector<TopicInfo> topics;
28→  auto topic_names_and_types = node_->get_topic_names_and_types();
29→
30→  for (const auto& [topic_name, topic_types] : topic_names_and_types) {
31→    if (should_filter_topic(topic_name)) {
32→      continue;
33→    }
34→
35→    if (!topic_types.empty()) {
36→      TopicInfo info;
37→      info.name = topic_name;
38→      info.type = topic_types[0];
39→      topics.push_back(info);
40→    }
41→  }
42→
43→  return topics;
44→}
45→
46→bool TopicDiscovery::should_filter_topic(const std::string& topic_name) const {
47→  static const std::vector<std::string> kSystemTopics = {"/rosout", "/parameter_events", "/robot_description"};
48→
49→  for (const auto& system_topic : kSystemTopics) {
50→    if (topic_name == system_topic) {
51→      return true;
52→    }
53→  }
54→
55→  if (topic_name.find("/_") == 0) {
56→    return true;
57→  }
58→
59→  return false;
60→}
